enum Status {
    Pending,
    Approved,
    Rejected,
}

fn handle_status(status: &Status) {
   match status {
       Status::Pending => println!("Still waiting...")
       Status::Approved => println!("You’re good!")
       Status::Rejected => println!("Better luck next time.")
    }
}

fn main() {
   let s = Status::Approved;
   handle_status(&s);
}

